     5→//! VVC Commit - Core commit infrastructure
     6→//!
     7→//! Provides atomic commit workflow: lock, stage, guard, commit.
     8→//! Used by vvx commit and JJK commands for consistent commit handling.
     9→//!
    10→//! ## Usage Patterns
    11→//!
    12→//! ### Simple commit (lock acquired and released automatically):
    13→//! ```ignore
    14→//! let exit_code = vvc::commit(&args);
    15→//! ```
    16→//!
    17→//! ### Protected operation (hold lock across multiple steps):
    18→//! ```ignore
    19→//! let lock = vvc::vvcc_CommitLock::vvcc_acquire()?;
    20→//! // ... do work while holding lock ...
    21→//! let hash = lock.vvcc_commit(&args)?;
    22→//! // lock released when dropped
    23→//! ```
    24→//!
    25→//! Exit codes:
    26→//!   0 - Success (commit hash printed to stdout)
    27→//!   1 - Failure (lock held, guard failed, claude failed, commit failed)
    28→
    29→use std::process::Command;
    30→
    31→use crate::vvcg_guard;
    32→
    33→/// Lock reference path for commit operations
    34→const VVCC_LOCK_REF: &str = "refs/vvg/locks/vvx";
    35→
    36→/// Arguments for commit operation
    37→///
    38→/// Note: No Default impl - callers must explicitly specify all fields,
    39→/// including size limits. Use VVCG_SIZE_LIMIT/VVCG_WARN_LIMIT constants
    40→/// for standard behavior.
    41→#[derive(Debug, Clone)]
    42→pub struct vvcc_CommitArgs {
    43→    /// Prefix string to prepend to commit message (e.g., "[jj:BRAND][F00/silks]")
    44→    pub prefix: Option<String>,
    45→    /// Commit message; if absent, invoke claude to generate from diff
    46→    pub message: Option<String>,
    47→    /// Allow empty commits (for chalk markers)
    48→    pub allow_empty: bool,
    49→    /// Skip 'git add -A' (respect pre-staged files)
    50→    pub no_stage: bool,
    51→    /// Size limit in bytes (use VVCG_SIZE_LIMIT for standard behavior)
    52→    pub size_limit: u64,
    53→    /// Warning threshold in bytes (use VVCG_WARN_LIMIT for standard behavior)
    54→    pub warn_limit: u64,
    55→}
    56→
    57→/// RAII guard that holds the commit lock.
    58→///
    59→/// The lock is automatically released when the guard is dropped, ensuring
    60→/// no code path can leak the lock. Use this when you need to hold the lock
    61→/// across multiple operations (e.g., modify gallops, then commit).
    62→///
    63→/// ## Example
    64→/// ```ignore
    65→/// let lock = vvcc_CommitLock::vvcc_acquire()?;
    66→/// // Do protected work here...
    67→/// let hash = lock.vvcc_commit(&args)?;
    68→/// // Lock released when `lock` goes out of scope
    69→/// ```
    70→pub struct vvcc_CommitLock {
    71→    /// Private field prevents external construction
    72→    _private: (),
    73→}
    74→
    75→impl vvcc_CommitLock {
    76→    /// Acquire the commit lock.
    77→    ///
    78→    /// Returns `Err` if the lock is already held by another operation.
    79→    /// The lock is held until this `vvcc_CommitLock` is dropped.
    80→    pub fn vvcc_acquire() -> Result<Self, String> {
    81→        zvvcc_acquire_lock()?;
    82→        Ok(vvcc_CommitLock { _private: () })
    83→    }
    84→
    85→    /// Perform a commit while holding the lock.
    86→    ///
    87→    /// This does NOT release the lock - the caller retains the guard
    88→    /// and can perform additional operations if needed.
    89→    ///
    90→    /// Returns the commit hash on success.
    91→    pub fn vvcc_commit(&self, args: &vvcc_CommitArgs) -> Result<String, String> {
    92→        zvvcc_run_commit_workflow(args)
    93→    }
    94→}
    95→
    96→impl Drop for vvcc_CommitLock {
    97→    fn drop(&mut self) {
    98→        zvvcc_release_lock();
    99→    }
   100→}
   101→
   102→/// Acquire the commit lock using git update-ref
   103→fn zvvcc_acquire_lock() -> Result<(), String> {
   104→    let head_output = Command::new("git")
   105→        .args(["rev-parse", "HEAD"])
   106→        .output()
   107→        .map_err(|e| format!("Failed to run git rev-parse: {}", e))?;
   108→
   109→    let lock_value = if head_output.status.success() {
   110→        String::from_utf8_lossy(&head_output.stdout).trim().to_string()
   111→    } else {
   112→        "0000000000000000000000000000000000000000".to_string()
   113→    };
   114→
   115→    let result = Command::new("git")
   116→        .args(["update-ref", VVCC_LOCK_REF, &lock_value, ""])
   117→        .output()
   118→        .map_err(|e| format!("Failed to run git update-ref: {}", e))?;
   119→
   120→    if result.status.success() {
   121→        Ok(())
   122→    } else {
   123→        Err("Another commit in progress - lock held".to_string())
   124→    }
   125→}
   126→
   127→/// Release the commit lock
   128→fn zvvcc_release_lock() {
   129→    let _ = Command::new("git")
   130→        .args(["update-ref", "-d", VVCC_LOCK_REF])
   131→        .output();
   132→}
   133→
   134→/// Stage all changes including untracked files with 'git add -A'
   135→fn zvvcc_stage_changes() -> Result<(), String> {
   136→    let result = Command::new("git")
   137→        .args(["add", "-A"])
   138→        .output()
   139→        .map_err(|e| format!("Failed to run git add: {}", e))?;
   140→
   141→    if result.status.success() {
   142→        eprintln!("commit: staged all changes");
   143→        Ok(())
   144→    } else {
   145→        Err(format!(
   146→            "git add -A failed: {}",
   147→            String::from_utf8_lossy(&result.stderr)
   148→        ))
   149→    }
   150→}
   151→
   152→/// Check if there are staged changes
   153→fn zvvcc_has_staged_changes() -> Result<bool, String> {
   154→    let result = Command::new("git")
   155→        .args(["diff", "--cached", "--quiet"])
   156→        .output()
   157→        .map_err(|e| format!("Failed to run git diff: {}", e))?;
   158→
   159→    Ok(!result.status.success())
   160→}
   161→
   162→/// Run size guard check on staged content
   163→fn zvvcc_run_guard(args: &vvcc_CommitArgs) -> Result<(), String> {
   164→    let guard_args = vvcg_guard::vvcg_GuardArgs {
   165→        limit: args.size_limit,
   166→        warn: args.warn_limit,
   167→    };
   168→
   169→    let result = vvcg_guard::vvcg_run(&guard_args, None);
   170→
   171→    match result {
   172→        0 => Ok(()),
   173→        1 => Err("Staged content exceeds size limit".to_string()),
   174→        2 => {
   175→            eprintln!("commit: WARNING - staged content near size limit");
   176→            Ok(())
   177→        }
   178→        _ => Err(format!("Guard returned unexpected code: {}", result)),
   179→    }
   180→}
   181→
   182→/// Get the staged diff for commit message generation
   183→fn zvvcc_get_staged_diff() -> Result<String, String> {
   184→    let output = Command::new("git")
   185→        .args(["diff", "--cached"])
   186→        .output()
   187→        .map_err(|e| format!("Failed to run git diff: {}", e))?;
   188→
   189→    if !output.status.success() {
   190→        return Err("git diff --cached failed".to_string());
   191→    }
   192→
   193→    Ok(String::from_utf8_lossy(&output.stdout).to_string())
   194→}
   195→
   196→/// Generate commit message using claude CLI
   197→fn zvvcc_generate_message_with_claude(diff: &str) -> Result<String, String> {
   198→    let prompt = format!(
   199→        "Generate a concise commit message for this diff:\n\n<diff>\n{}\n</diff>\n\nRespond with only the commit message, no explanation.",
   200→        diff
   201→    );
   202→
   203→    eprintln!("commit: invoking claude for commit message...");
   204→
   205→    let output = Command::new("claude")
   206→        .args([
   207→            "--print",
   208→            "--system-prompt",
   209→            "Output only a conventional git commit message. No explanation or commentary. Do not wrap in markdown code blocks.",
   210→            "--model",
   211→            "haiku",
   212→            "--no-session-persistence",
   213→            &prompt,
   214→        ])
   215→        .output()
   216→        .map_err(|e| format!("Failed to invoke claude: {}", e))?;
   217→
   218→    if !output.status.success() {
   219→        let stderr = String::from_utf8_lossy(&output.stderr);
   220→        return Err(format!("claude --print failed: {}", stderr));
   221→    }
   222→
   223→    let message = String::from_utf8_lossy(&output.stdout).trim().to_string();
   224→
   225→    // Strip markdown code blocks if Claude wrapped the response
   226→    let message = if message.starts_with("```") {
   227→        let after_opening = message.find('\n').map(|i| i + 1).unwrap_or(0);
   228→        let before_closing = message.rfind("```").unwrap_or(message.len());
   229→        if before_closing > after_opening {
   230→            message[after_opening..before_closing].trim().to_string()
   231→        } else {
   232→            message
   233→        }
   234→    } else {
   235→        message
   236→    };
   237→
   238→    // Strip Co-Authored-By trailer if Claude CLI added it from global settings
   239→    let message: String = message
   240→        .lines()
   241→        .filter(|line| !line.starts_with("Co-Authored-By:"))
   242→        .collect::<Vec<_>>()
   243→        .join("\n")
   244→        .trim()
   245→        .to_string();
   246→
   247→    if message.is_empty() {
   248→        return Err("claude returned empty message".to_string());
   249→    }
   250→
   251→    eprintln!("commit: claude generated message");
   252→    Ok(message)
   253→}
   254→
   255→/// Format the full commit message with prefix and co-author
   256→fn zvvcc_format_commit_message(prefix: Option<&str>, message: &str) -> String {
   257→    let mut full_message = String::new();
   258→
   259→    if let Some(p) = prefix {
   260→        full_message.push_str(p);
   261→    }
   262→
   263→    full_message.push_str(message);
   264→
   265→    full_message
   266→}
   267→
   268→/// Execute the git commit
   269→fn zvvcc_execute_commit(message: &str, allow_empty: bool) -> Result<String, String> {
   270→    let mut args = vec!["commit", "-m", message];
   271→
   272→    if allow_empty {
   273→        args.push("--allow-empty");
   274→    }
   275→
   276→    let output = Command::new("git")
   277→        .args(&args)
   278→        .output()
   279→        .map_err(|e| format!("Failed to run git commit: {}", e))?;
   280→
   281→    if !output.status.success() {
   282→        let stderr = String::from_utf8_lossy(&output.stderr);
   283→        return Err(format!("git commit failed: {}", stderr));
   284→    }
   285→
   286→    let hash_output = Command::new("git")
   287→        .args(["rev-parse", "HEAD"])
   288→        .output()
   289→        .map_err(|e| format!("Failed to get commit hash: {}", e))?;
   290→
   291→    if !hash_output.status.success() {
   292→        return Err("Failed to retrieve commit hash".to_string());
   293→    }
   294→
   295→    Ok(String::from_utf8_lossy(&hash_output.stdout)
   296→        .trim()
   297→        .to_string())
   298→}
   299→
   300→/// Run the commit workflow.
   301→///
   302→/// Returns exit code: 0 for success, 1 for failure.
   303→/// On success, prints commit hash to stdout.
   304→///
   305→/// This is the simple API that acquires and releases the lock automatically.
   306→/// For operations that need to hold the lock across multiple steps, use
   307→/// `vvcc_CommitLock::vvcc_acquire()` instead.
   308→pub fn vvcc_run(args: &vvcc_CommitArgs) -> i32 {
   309→    let lock = match vvcc_CommitLock::vvcc_acquire() {
   310→        Ok(l) => l,
   311→        Err(e) => {
   312→            eprintln!("commit: error: {}", e);
   313→            return 1;
   314→        }
   315→    };
   316→
   317→    match lock.vvcc_commit(args) {
   318→        Ok(hash) => {
   319→            println!("{}", hash);
   320→            eprintln!("commit: success");
   321→            0
   322→        }
   323→        Err(e) => {
   324→            eprintln!("commit: error: {}", e);
   325→            1
   326→        }
   327→    }
   328→    // lock dropped here, releasing the git ref lock
   329→}
   330→
   331→/// Inner workflow that can return Result for cleaner error handling
   332→fn zvvcc_run_commit_workflow(args: &vvcc_CommitArgs) -> Result<String, String> {
   333→    if !args.no_stage {
   334→        zvvcc_stage_changes()?;
   335→    }
   336→
   337→    if !args.allow_empty && !zvvcc_has_staged_changes()? {
   338→        return Err("Nothing to commit".to_string());
   339→    }
   340→
   341→    zvvcc_run_guard(args)?;
   342→
   343→    let message = match &args.message {
   344→        Some(m) => m.clone(),
   345→        None => {
   346→            let diff = zvvcc_get_staged_diff()?;
   347→            if diff.is_empty() && !args.allow_empty {
   348→                return Err("No diff to generate message from".to_string());
   349→            }
   350→            zvvcc_generate_message_with_claude(&diff)?
   351→        }
   352→    };
   353→
   354→    let full_message = zvvcc_format_commit_message(args.prefix.as_deref(), &message);
   355→
   356→    zvvcc_execute_commit(&full_message, args.allow_empty)
   357→}
