   107→/// Change status for a staged file
   108→#[derive(Debug, Clone, Copy, PartialEq)]
   109→enum zvvcg_ChangeStatus {
   110→    Added,
   111→    Modified,
   112→    Deleted,
   113→}
   114→
   115→/// Get the change status of a staged file (A/M/D)
   116→fn zvvcg_get_change_status(path: &str, repo_dir: Option<&Path>) -> Result<zvvcg_ChangeStatus, String> {
   117→    let mut cmd = Command::new("git");
   118→    cmd.args(["diff", "--cached", "--name-status", "--", path]);
   119→    if let Some(dir) = repo_dir {
   120→        cmd.current_dir(dir);
   121→    }
   122→    let output = cmd
   123→        .output()
   124→        .map_err(|e| format!("Failed to run git diff --name-status for {}: {}", path, e))?;
   125→
   126→    if !output.status.success() {
   127→        return Err(format!("git diff --cached --name-status -- {} failed", path));
   128→    }
   129→
   130→    let stdout = String::from_utf8_lossy(&output.stdout);
   131→    let line = stdout.trim();
   132→
   133→    if line.is_empty() {
   134→        // File not in diff - shouldn't happen if called from staged files list
   135→        return Err(format!("File {} not found in staged changes", path));
   136→    }
   137→
   138→    // Format: "A\tpath" or "M\tpath" or "D\tpath" (or R/C with rename info)
   139→    let status_char = line.chars().next().unwrap_or('?');
   140→
   141→    match status_char {
   142→        'A' => Ok(zvvcg_ChangeStatus::Added),
   143→        'M' => Ok(zvvcg_ChangeStatus::Modified),
   144→        'D' => Ok(zvvcg_ChangeStatus::Deleted),
   145→        'R' | 'C' => Ok(zvvcg_ChangeStatus::Modified), // Rename/Copy treated as modified
   146→        _ => Err(format!("Unknown status '{}' for {}", status_char, path)),
   147→    }
   148→}
