   150→/// Check if a modified file is binary
   151→///
   152→/// Uses git diff --numstat which reports `-\t-\t<path>` for binary files.
   153→fn zvvcg_is_binary(path: &str, repo_dir: Option<&Path>) -> Result<bool, String> {
   154→    let mut cmd = Command::new("git");
   155→    cmd.args(["diff", "--cached", "--numstat", "--", path]);
   156→    if let Some(dir) = repo_dir {
   157→        cmd.current_dir(dir);
   158→    }
   159→    let output = cmd
   160→        .output()
   161→        .map_err(|e| format!("Failed to run git diff --numstat for {}: {}", path, e))?;
   162→
   163→    if !output.status.success() {
   164→        return Err(format!("git diff --cached --numstat -- {} failed", path));
   165→    }
   166→
   167→    let stdout = String::from_utf8_lossy(&output.stdout);
   168→    let line = stdout.trim();
   169→
   170→    // Binary files show: "-\t-\t<path>"
   171→    // Text files show: "<added>\t<removed>\t<path>"
   172→    Ok(line.starts_with("-\t-\t"))
   173→}
