   175→/// Get the blob size for a staged file
   176→fn zvvcg_get_blob_size(path: &str, repo_dir: Option<&Path>) -> Result<u64, String> {
   177→    // Get staged blob info: mode, sha, stage, path
   178→    let mut cmd = Command::new("git");
   179→    cmd.args(["ls-files", "--cached", "-s", "--", path]);
   180→    if let Some(dir) = repo_dir {
   181→        cmd.current_dir(dir);
   182→    }
   183→    let output = cmd
   184→        .output()
   185→        .map_err(|e| format!("Failed to run git ls-files for {}: {}", path, e))?;
   186→
   187→    if !output.status.success() {
   188→        return Err(format!("git ls-files --cached -s -- {} failed", path));
   189→    }
   190→
   191→    let stdout = String::from_utf8_lossy(&output.stdout);
   192→    let line = stdout.trim();
   193→
   194→    if line.is_empty() {
   195→        return Ok(0);
   196→    }
   197→
   198→    // Parse: "100644 <sha> 0\t<path>"
   199→    let parts: Vec<&str> = line.split_whitespace().collect();
   200→    if parts.len() < 2 {
   201→        return Err(format!("Unexpected git ls-files output for {}: {}", path, line));
   202→    }
   203→
   204→    let blob_sha = parts[1];
   205→
   206→    // Get actual blob size
   207→    let mut cmd = Command::new("git");
   208→    cmd.args(["cat-file", "-s", blob_sha]);
   209→    if let Some(dir) = repo_dir {
   210→        cmd.current_dir(dir);
   211→    }
   212→    let output = cmd
   213→        .output()
   214→        .map_err(|e| format!("Failed to run git cat-file for {}: {}", blob_sha, e))?;
   215→
   216→    if !output.status.success() {
   217→        return Err(format!("git cat-file -s {} failed", blob_sha));
   218→    }
   219→
   220→    let size_str = String::from_utf8_lossy(&output.stdout);
   221→    size_str
   222→        .trim()
   223→        .parse::<u64>()
   224→        .map_err(|e| format!("Failed to parse blob size for {}: {}", path, e))
   225→}
   226→
   227→/// Get the diff output size for a modified text file
   228→fn zvvcg_get_text_diff_size(path: &str, repo_dir: Option<&Path>) -> Result<u64, String> {
   229→    let mut cmd = Command::new("git");
